import React, { useState, useEffect, useMemo } from "react";

const toCents = (val) => Math.round(val * 100);
const fromCents = (val) => (val / 100).toFixed(2);

export default function SplitPayment() {
    const [total, setTotal] = useState(1000);
    const [participants, setParticipants] = useState([
        { id: 1, name: "A", amount: 500 },
        { id: 2, name: "B", amount: 500 }
    ]);
    const [isEqualSplit, setIsEqualSplit] = useState(true);

    // Equal split logic
    useEffect(() => {
        if (isEqualSplit && participants.length > 0) {
            const totalCents = toCents(total);
            const equalCents = Math.floor(totalCents / participants.length);

            let remainder = totalCents % participants.length;

            const updated = participants.map((p, index) => {
                let amt = equalCents;
                if (remainder > 0) {
                    amt += 1;
                    remainder--;
                }
                return { ...p, amount: parseFloat(fromCents(amt)) };
            });

            setParticipants(updated);
        }
    }, [total, participants.length, isEqualSplit]);

    // Total allocated
    const totalAllocated = useMemo(() => {
        return participants.reduce((sum, p) => sum + p.amount, 0);
    }, [participants]);

    const remaining = +(total - totalAllocated).toFixed(2);

    // Handle amount change
    const handleAmountChange = (id, value) => {
        setIsEqualSplit(false);

        const updated = participants.map((p) =>
            p.id === id ? { ...p, amount: parseFloat(value) || 0 } : p
        );

        setParticipants(updated);
    };

    // Auto-adjust last participant
    const adjustLast = () => {
        if (participants.length === 0) return;

        const totalCents = toCents(total);

        const sumExceptLast = participants
            .slice(0, -1)
            .reduce((sum, p) => sum + toCents(p.amount), 0);

        const lastAmount = totalCents - sumExceptLast;

        const updated = [...participants];
        updated[updated.length - 1].amount = parseFloat(fromCents(lastAmount));

        setParticipants(updated);
    };

    // Add participant
    const addParticipant = () => {
        setParticipants((prev) => [
            ...prev,
            {
                id: Date.now(),
                name: `User ${prev.length + 1}`,
                amount: 0
            }
        ]);
    };

    // Remove participant
    const removeParticipant = (id) => {
        setParticipants((prev) => prev.filter((p) => p.id !== id));
    };

    return (
        <div style={{ maxWidth: 500, margin: "20px auto", fontFamily: "sans-serif" }}>
            <h2>Split Payment</h2>

            {/* Total */}
            <div>
                <label>Total Amount:</label>
                <input
                    type="number"
                    value={total}
                    onChange={(e) => setTotal(parseFloat(e.target.value) || 0)}
                />
            </div>

            {/* Equal Split Toggle */}
            <label>
                <input
                    type="checkbox"
                    checked={isEqualSplit}
                    onChange={() => setIsEqualSplit((prev) => !prev)}
                />
                Equal Split
            </label>

            {/* Participants */}
            <div>
                {participants.map((p, index) => (
                    <div key={p.id} style={{ display: "flex", gap: 10, marginTop: 10 }}>
                        <input
                            type="text"
                            value={p.name}
                            onChange={(e) => {
                                const updated = [...participants];
                                updated[index].name = e.target.value;
                                setParticipants(updated);
                            }}
                        />

                        <input
                            type="number"
                            value={p.amount}
                            disabled={isEqualSplit}
                            onChange={(e) =>
                                handleAmountChange(p.id, e.target.value)
                            }
                        />

                        <button onClick={() => removeParticipant(p.id)}>❌</button>
                    </div>
                ))}
            </div>

            {/* Actions */}
            <div style={{ marginTop: 10 }}>
                <button onClick={addParticipant}>Add Participant</button>
                <button onClick={adjustLast} style={{ marginLeft: 10 }}>
                    Adjust Last
                </button>
            </div>

            {/* Summary */}
            <div style={{ marginTop: 20 }}>
                <p>Total Allocated: {totalAllocated.toFixed(2)}</p>
                <p>Remaining: {remaining}</p>

                {remaining !== 0 && (
                    <p style={{ color: "red" }}>
                        Amount mismatch! Please adjust values.
                    </p>
                )}
            </div>
        </div>
    );
}
